        public IActionResult Search(string username, string sort)
        {
            // VULNERABLE: building dynamic SQL with string concatenation
            string sql = "SELECT Id, Username, Email FROM Users WHERE 1=1";

            if (!string.IsNullOrEmpty(username))
            {
                sql += " AND Username LIKE '%" + username + "%'"; // Directly injecting user input
            }

            if (!string.IsNullOrEmpty(sort))
            {
                // Attacker can control ORDER BY clause here
                sql += " ORDER BY " + sort;
            }

            using (var connection = new SqlConnection(ConnectionString))
            using (var command = new SqlCommand(sql, connection))
            {
                connection.Open();
                var table = new DataTable();
                using (var reader = command.ExecuteReader())
                {
                    table.Load(reader);
                }

                return Ok(table);
            }
        }
    }
}
```

**Attack Payload** (if applicable):
```sql
username=' OR '1'='1'--

-- Or to abuse ORDER BY for data exploration or DoS
sort=CASE WHEN (SELECT COUNT(*) FROM Users) > 0 THEN Username ELSE Id END
```

**Why This Is Dangerous**:
- User input is directly concatenated into the SQL string, allowing attackers to change the query logic.
- `LIKE '%" + username + "%'` makes it easy to inject `' OR '1'='1'--` and bypass filters or dump data.
- Dynamic `ORDER BY` from user input can be used for injection, heavy queries for DoS, or to explore the schema.

