        public IActionResult AdvancedSearch([FromBody] UserSearchRequest request)
        {
            // Defense in depth: basic rate limiting hint (implement via middleware)
            // e.g., IP-based limits using ASP.NET Core Rate Limiting middleware

            if (request.PageSize is < 1 or > 100)
            {
                return BadRequest("PageSize must be between 1 and 100.");
            }

            string sortColumn = "Username";
            if (!string.IsNullOrEmpty(request.SortBy))
            {
                if (!AllowedSortColumns.Contains(request.SortBy))
                {
                    return BadRequest("Invalid sort column.");
                }
                sortColumn = request.SortBy;
            }

            bool sortDesc = request.Desc;

            var sql = new StringBuilder();
            sql.Append("SELECT Id, Username, Email, Age, CreatedAt FROM Users WHERE 1=1");

            var parameters = new List<SqlParameter>();

            // Build dynamic filters safely
            if (!string.IsNullOrWhiteSpace(request.Username))
            {
                sql.Append(" AND Username LIKE @username");
                parameters.Add(new SqlParameter("@username", SqlDbType.NVarChar, 50)
                {
                    Value = "%" + request.Username + "%"
                });
            }

            if (!string.IsNullOrWhiteSpace(request.Email))
            {
                sql.Append(" AND Email LIKE @email");
                parameters.Add(new SqlParameter("@email", SqlDbType.NVarChar, 100)
                {
                    Value = "%" + request.Email + "%"
                });
            }

            if (request.MinAge.HasValue)
            {
                sql.Append(" AND Age >= @minAge");
                parameters.Add(new SqlParameter("@minAge", SqlDbType.Int) { Value = request.MinAge.Value });
            }

            if (request.MaxAge.HasValue)
            {
                sql.Append(" AND Age <= @maxAge");
                parameters.Add(new SqlParameter("@maxAge", SqlDbType.Int) { Value = request.MaxAge.Value });
            }

            if (request.RegisteredAfter.HasValue)
            {
                sql.Append(" AND CreatedAt >= @registeredAfter");
                parameters.Add(new SqlParameter("@registeredAfter", SqlDbType.DateTime2)
                {
