                });
            }

            if (request.RegisteredBefore.HasValue)
            {
                sql.Append(" AND CreatedAt <= @registeredBefore");
                parameters.Add(new SqlParameter("@registeredBefore", SqlDbType.DateTime2)
                {
                    Value = request.RegisteredBefore.Value
                });
            }

            // Safe ORDER BY using allow-listed column and fixed ASC/DESC token
            sql.Append($" ORDER BY {sortColumn} {(sortDesc ? "DESC" : "ASC")}");

            // Pagination (defense against large result sets)
            int offset = (request.Page - 1) * request.PageSize;
            sql.Append(" OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY");
            parameters.Add(new SqlParameter("@offset", SqlDbType.Int) { Value = offset });
            parameters.Add(new SqlParameter("@pageSize", SqlDbType.Int) { Value = request.PageSize });

            try
            {
                using var connection = new SqlConnection(ConnectionString);
                using var command = new SqlCommand(sql.ToString(), connection);
                command.Parameters.AddRange(parameters.ToArray());

