            string sql = "SELECT * FROM Users WHERE UserName = '" + username + "'";

            var users = _db.Users
                .FromSqlRaw(sql) // Dangerous when sql is built from user input
                .ToList();

            return Ok(users);
        }
    }

    public class AppDbContext : DbContext
    {
        public DbSet<User> Users { get; set; } = null!;
    }

