            if (request.Page <= 0)
            {
                request.Page = 1;
            }

            if (!AllowedSortColumns.Contains(request.SortBy))
            {
                _logger.LogWarning("Invalid sort column: {SortBy}", request.SortBy);
                request.SortBy = "Username";
            }

            string sortDirection = request.SortDirection.Equals("desc", StringComparison.OrdinalIgnoreCase) ? "DESC" : "ASC";

            var sqlBuilder = new StringBuilder();
            sqlBuilder.AppendLine("SELECT Id, Username, Email");
            sqlBuilder.AppendLine("FROM Users");
            sqlBuilder.AppendLine("WHERE 1=1");

            var parameters = new List<SqlParameter>();

            // Dynamic filters with parameters only
            if (!string.IsNullOrWhiteSpace(request.Username))
            {
                sqlBuilder.AppendLine("AND Username LIKE @username");
                parameters.Add(new SqlParameter("@username", SqlDbType.NVarChar, 50)
                {
                    Value = "%" + request.Username.Trim() + "%"
                });
            }

            if (!string.IsNullOrWhiteSpace(request.Email))
            {
                sqlBuilder.AppendLine("AND Email LIKE @email");
                parameters.Add(new SqlParameter("@email", SqlDbType.NVarChar, 100)
                {
