                parameters.Add(new SqlParameter("@minId", SqlDbType.Int) { Value = request.MinId.Value });
            }

            if (request.MaxId.HasValue)
            {
                sqlBuilder.AppendLine("AND Id <= @maxId");
                parameters.Add(new SqlParameter("@maxId", SqlDbType.Int) { Value = request.MaxId.Value });
            }

            // Safe ORDER BY with whitelisted column & fixed direction string
            sqlBuilder.AppendLine($"ORDER BY {request.SortBy} {sortDirection}");

            // Pagination
            int offset = (request.Page - 1) * request.PageSize;
            sqlBuilder.AppendLine("OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY");
            parameters.Add(new SqlParameter("@offset", SqlDbType.Int) { Value = offset });
            parameters.Add(new SqlParameter("@pageSize", SqlDbType.Int) { Value = request.PageSize });

            string sql = sqlBuilder.ToString();

            // Rate limiting & monitoring: pretend we have middleware, add audit logs here
            _logger.LogInformation("User search requested from {IP} with filters: {@Request}", HttpContext.Connection.RemoteIpAddress?.ToString(), request);

            var results = new List<object>();

