        [HttpGet("users/search")]
        public IActionResult Search(string username)
        {
            // VULNERABLE: string concatenation in raw SQL
            string sql = "SELECT * FROM Users WHERE UserName = '" + username + "'";

            var users = _db.Users
                .FromSqlRaw(sql) // Executes attacker-controlled SQL
                .ToList();

            return Ok(users);
        }
    }

    public class AppDbContext : DbContext
    {
        public DbSet<User> Users { get; set; } = null!;
    }

    public class User
    {
        public int Id { get; set; }
        public string UserName { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
    }
}
```

**Attack Payload** (if applicable):
```sql
' OR 1=1; DROP TABLE Users; --
```

If the attacker calls:

```text
GET /users/search?username=' OR 1=1; DROP TABLE Users; --
```

the final SQL becomes:

```sql
SELECT * FROM Users WHERE UserName = '' OR 1=1; DROP TABLE Users; --'
```

This returns all users and then drops the `Users` table.

**Why This Is Dangerous**:
- User input is directly concatenated into SQL, allowing attackers to inject arbitrary SQL.
- `FromSqlRaw` executes the SQL as-is against the database with full privileges of the app's DB account.
- An attacker can exfiltrate sensitive data, modify records, or destroy tables, leading to major breaches similar to CVE-2023-34362.

**SECURE VERSION**:

