        [MaxLength(4)]
        public string? SortDir { get; set; } = "asc";     // "asc" or "desc"
    }

    [ApiController]
    [Route("api/[controller]")]
    public class UsersController : ControllerBase
    {
        private readonly AppDbContext _db;
        private readonly ILogger<UsersController> _logger;
        private readonly IConfiguration _config;

        private static readonly HashSet<string> AllowedSortColumns = new(StringComparer.OrdinalIgnoreCase)
        {
            "UserName", "Email", "Id"
        };

        public UsersController(AppDbContext db, ILogger<UsersController> logger, IConfiguration config)
        {
            _db = db;
            _logger = logger;
            _config = config;
        }

        // Example: GET /api/users/search?UserName=al&SortBy=Email&SortDir=desc
        [HttpGet("search")]
        public IActionResult AdvancedSearch([FromQuery] UserSearchRequest request)
        {
            try
            {
                // Layer 1: Basic model validation
                if (!ModelState.IsValid)
                {
                    return ValidationProblem(ModelState);
                }

                // Layer 2: Rate limiting check (simplified placeholder)
                if (IsRateLimited(HttpContext.Connection.RemoteIpAddress?.ToString()))
                {
                    _logger.LogWarning("Rate limit exceeded from {Ip}", HttpContext.Connection.RemoteIpAddress);
                    return StatusCode(429, "Too many requests");
                }

                // Layer 3: Build dynamic LINQ, not SQL text
                IQueryable<User> query = _db.Users.AsNoTracking();

                if (!string.IsNullOrWhiteSpace(request.UserName))
                {
                    string name = request.UserName.Trim();
                    query = query.Where(u => EF.Functions.Like(u.UserName, name + "%"));
                }

                if (!string.IsNullOrWhiteSpace(request.Email))
                {
                    string email = request.Email.Trim();
                    query = query.Where(u => u.Email == email);
                }

                // Whitelist sort column and direction
                string sortBy = request.SortBy ?? "UserName";
                if (!AllowedSortColumns.Contains(sortBy))
                {
                    _logger.LogWarning("Invalid sort column {SortBy} from {Ip}", sortBy, HttpContext.Connection.RemoteIpAddress);
                    sortBy = "UserName"; // fallback to safe default
                }

                bool descending = string.Equals(request.SortDir, "desc", StringComparison.OrdinalIgnoreCase);

                query = sortBy switch
                {
                    "Email" => descending ? query.OrderByDescending(u => u.Email) : query.OrderBy(u => u.Email),
                    "Id" => descending ? query.OrderByDescending(u => u.Id) : query.OrderBy(u => u.Id),
                    _ => descending ? query.OrderByDescending(u => u.UserName) : query.OrderBy(u => u.UserName)
                };

                int skip = (request.Page - 1) * request.PageSize;
                int total = query.Count();

                var users = query
                    .Skip(skip)
                    .Take(request.PageSize)
                    .ToList();

                // Audit logging (without sensitive data like passwords)
                _logger.LogInformation(
                    "User search from {Ip}: UserName={UserName}, Email={Email}, SortBy={SortBy}, SortDir={SortDir}, Page={Page}, PageSize={PageSize}, Total={Total}",
                    HttpContext.Connection.RemoteIpAddress,
                    request.UserName,
                    request.Email,
                    sortBy,
                    descending ? "desc" : "asc",
                    request.Page,
                    request.PageSize,
                    total
                );

                // Secure response object
                return Ok(new
                {
                    total,
                    page = request.Page,
                    pageSize = request.PageSize,
                    data = users.Select(u => new { u.Id, u.UserName, u.Email })
                });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error in AdvancedSearch");
                return StatusCode(500, "Internal server error");
            }
        }

